package com.finance.controller; import org.springframework.web.bind.annotation.*; import com.finance.model.Transaction; import java.math.BigDecimal; import java.time.LocalDate; @RestController @RequestMapping("/api/v1/transactions") public class TransactionController { @GetMapping("/{id}") public Transaction getTransactionById(@PathVariable String id) { return new Transaction(id, "Mock", new BigDecimal("100"), LocalDate.now()); } }
